import org.apache.commons.text.StringEscapeUtils;

public class XSSProtection {
    public static void main(String[] args) {
        // Simulating user input from a form field
        String userInput = "<script>alert('XSS Attack!')</script>";

        // Encoding the user input to prevent XSS attacks
        String safeUserInput = StringEscapeUtils.escapeHtml4(userInput);

        // Displaying the encoded user input on a webpage
        System.out.println("<div>" + safeUserInput + "</div>");
    }
}

### Explanation:
취약유형: Cross-Site Scripting (XSS)
